import{_ as i,W as a,X as e,Y as l}from"./framework-9a5142fa.js";const p={},r=l('<p>[toc]</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202502241421333.png" alt="image-20250224142145246"></p><h2 id="尺寸" tabindex="-1"><a class="header-anchor" href="#尺寸" aria-hidden="true">#</a> 尺寸</h2><p>装箱子？</p><h2 id="分辨率" tabindex="-1"><a class="header-anchor" href="#分辨率" aria-hidden="true">#</a> 分辨率</h2><p>1080P：1920x1080</p><p>2K：2560x1440</p><p>4K：3840x2160</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202502241424098.png" alt="image-20250224142453048"></p><h2 id="色域" tabindex="-1"><a class="header-anchor" href="#色域" aria-hidden="true">#</a> 色域</h2><p>办公：100%sRGB</p><p>平面创作：100%AdobeRGB</p><p>视频游戏：93%以上 DCI-P3</p><p><img src="https://cdn.jsdelivr.net/gh/sword4869/pic1@main/images/202502241426188.png" alt="image-20250224142654118"></p><h2 id="色准" tabindex="-1"><a class="header-anchor" href="#色准" aria-hidden="true">#</a> 色准</h2><p>显示器能够准确还原输入信号的能力，即颜色偏差的范围。</p><p>色准高了，色域广也没用，颜色偏差还是严重。</p><ul><li>ΔE&lt;2：专业认识也很难看出</li><li>2&lt;ΔE&lt;5：非专业人士看不出</li><li>ΔE&gt;5：普通人也能看出</li></ul><h2 id="色深" tabindex="-1"><a class="header-anchor" href="#色深" aria-hidden="true">#</a> 色深</h2><p>颜色过渡是否平滑。</p><ul><li>办公：6bit足矣</li><li>娱乐：8bit以上</li></ul><p>FRC可以让8bit模拟10bit，上一个层次</p><h2 id="刷新率" tabindex="-1"><a class="header-anchor" href="#刷新率" aria-hidden="true">#</a> 刷新率</h2><p>刷新率越高，对显卡的要求也越高。</p><ul><li>办公：60HZ</li><li>3A单机：144HZ以下</li><li>FPS：240HZ</li></ul><h2 id="响应时间" tabindex="-1"><a class="header-anchor" href="#响应时间" aria-hidden="true">#</a> 响应时间</h2><p>黑白响应时间（黑白转化）：10-20ms</p><p>灰阶响应时间GTG（相近颜色转化）：1-3ms</p><p>大部分用的是灰阶。</p><h2 id="屏幕材质" tabindex="-1"><a class="header-anchor" href="#屏幕材质" aria-hidden="true">#</a> 屏幕材质</h2><p>背光板负责发光，面板负责将光源呈现出来。</p><p>面板材质：TN、VA、IPS</p><p>背光技术：LED（主流）、MiniLED（升级，贵）、OLED（响应快、更薄、但贵和易烧屏）、MicroLED（超好，超贵）</p><p>TN：</p><ul><li>优点:灰阶响应速度快</li><li>缺点:颜色差、对比度差、可视角差</li><li>适合:FPS发烧友（不适合玩3A游戏）和低预算用户（一百两百的显示器就是这种）</li></ul><p>VA：</p><ul><li>柔性，基本用来做曲面屏。1000R、1800R代表弧度越高</li><li>对比度高，颜色鲜艳</li><li>响应时间长，游戏有拖影</li><li>改进技术：华新HVA响应低一些</li></ul><p>IPS：</p><ul><li>响应处于TN和VN中间。</li><li>价格稍高</li><li>漏光</li><li>改进技术：LG的Nano IPS（专注色准，98%DCI-P3，4-5ms GTG）、友达的Fast IPS（专注响应，95%DCI-P3，3ms GTG）</li></ul><p>总结</p><ul><li><p>TN面板:预算低的用户、FPS发烧友</p></li><li><p>VA面 板:有环抱效果、带鱼屏</p></li><li><p>IPS面板:生产力用户、3A游戏、轻度FPS玩家</p></li></ul><h2 id="" tabindex="-1"><a class="header-anchor" href="#" aria-hidden="true">#</a></h2><p>AMD的FreeSync、NVidia的G-SYnc是防止显卡和显示器画面撕裂的问题。</p><h2 id="认证" tabindex="-1"><a class="header-anchor" href="#认证" aria-hidden="true">#</a> 认证</h2><p>第三方认证</p><p>VESA DisplayHDR 400-1400，从低到高。600才有意义，更低就是图一乐。</p>',46),h=[r];function d(t,n){return a(),e("div",null,h)}const c=i(p,[["render",d],["__file","显示器.html.vue"]]);export{c as default};
